import{_ as t,o as a,c as r,a2 as i}from"./chunks/framework.N9BN-Nr4.js";const u=JSON.parse('{"title":"MTG Treachery","description":"","frontmatter":{},"headers":[],"relativePath":"formats/bang-like/sources/mtg-treachery.md","filePath":"formats/bang-like/sources/mtg-treachery.md","lastUpdated":1782025909000}'),l={name:"formats/bang-like/sources/mtg-treachery.md"};function d(s,e,n,o,h,c){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="mtg-treachery" tabindex="-1">MTG Treachery <a class="header-anchor" href="#mtg-treachery" aria-label="Permalink to &quot;MTG Treachery&quot;">​</a></h1><p>Source: <a href="https://mtgtreachery.net/en/" target="_blank" rel="noreferrer">https://mtgtreachery.net/en/</a></p><p>MTG Treachery is a maintained fan-made multiplayer variant for Magic: The Gathering, optimized for Commander/EDH. It is in the same broad family as Kingdoms, Usurper, Throne Magic, Assassin, and BANG!-style variants.</p><p>The source site provides rules, printable Identity cards, a card oracle, web play tools, a Discord bot, and comprehensive rules.</p><h2 id="site-sections" tabindex="-1">Site Sections <a class="header-anchor" href="#site-sections" aria-label="Permalink to &quot;Site Sections&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Section</th><th>Purpose</th></tr></thead><tbody><tr><td>How to Play</td><td>Introductory rules and role overview.</td></tr><tr><td>Game Materials</td><td>Printable Identity cards, tokens, and rule cards.</td></tr><tr><td>Banlist</td><td>Additional caution list beyond the base format&#39;s ban list.</td></tr><tr><td>Play by Web</td><td>Browser tools for playing without printed cards.</td></tr><tr><td>Play on Discord</td><td>Discord bot support.</td></tr><tr><td>Oracle</td><td>Searchable Identity card database.</td></tr><tr><td>Comprehensive Rules</td><td>Formal rules add-on for the Treachery variant.</td></tr></tbody></table><h2 id="premise" tabindex="-1">Premise <a class="header-anchor" href="#premise" aria-label="Permalink to &quot;Premise&quot;">​</a></h2><p>Treachery adds a custom card type, <strong>Identity</strong>, to multiplayer Magic. Each player receives an Identity card that defines their role, allies, and win condition.</p><p>The format is built around table politics, bluffing, and secret information. Players can lie, hide their role, and choose when to reveal powerful one-shot abilities.</p><p>The source recommends Treachery for 5-7 players, though it supports 4 and 8+ players.</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>Team / Objective</th></tr></thead><tbody><tr><td>Leader</td><td>The Leader and Guardians win if they are the last players standing.</td></tr><tr><td>Guardian</td><td>Guardians help the Leader and win or lose with the Leader.</td></tr><tr><td>Assassin</td><td>Assassins win if the Leader is eliminated.</td></tr><tr><td>Traitor</td><td>The Traitor wins by being the last player standing.</td></tr></tbody></table><p>The Traitor usually needs to remove the Assassins before eliminating the Leader, because if the Leader dies while an Assassin can claim victory, the Assassin team wins.</p><h2 id="identity-cards" tabindex="-1">Identity Cards <a class="header-anchor" href="#identity-cards" aria-label="Permalink to &quot;Identity Cards&quot;">​</a></h2><p>Identity cards are custom nontraditional Magic cards. They remain in the command zone throughout the game.</p><p>An Identity&#39;s subtype defines the player&#39;s role. Except for the Leader, Identities are usually secret and face down.</p><p>Most non-Leader Identities have an <strong>Unveil</strong> ability. Unveiling turns the Identity face up and triggers a powerful ability, but it also reveals the player&#39;s role.</p><p>Players are considered opponents to each other while their Identity cards are face down.</p><h2 id="starting-a-game" tabindex="-1">Starting A Game <a class="header-anchor" href="#starting-a-game" aria-label="Permalink to &quot;Starting A Game&quot;">​</a></h2><p>Prepare an Identity deck based on player count, shuffle it, and deal one Identity face down to each player. Each player secretly looks at their Identity. The Leader reveals themself and starts the game.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Players</th><th style="text-align:right;">Leader</th><th style="text-align:right;">Traitor</th><th style="text-align:right;">Assassin</th><th style="text-align:right;">Guardian</th></tr></thead><tbody><tr><td style="text-align:right;">4</td><td style="text-align:right;">1</td><td style="text-align:right;">1</td><td style="text-align:right;">2</td><td style="text-align:right;">0</td></tr><tr><td style="text-align:right;">5</td><td style="text-align:right;">1</td><td style="text-align:right;">1</td><td style="text-align:right;">2</td><td style="text-align:right;">1</td></tr><tr><td style="text-align:right;">6</td><td style="text-align:right;">1</td><td style="text-align:right;">1</td><td style="text-align:right;">3</td><td style="text-align:right;">1</td></tr><tr><td style="text-align:right;">7</td><td style="text-align:right;">1</td><td style="text-align:right;">1</td><td style="text-align:right;">3</td><td style="text-align:right;">2</td></tr><tr><td style="text-align:right;">8</td><td style="text-align:right;">1</td><td style="text-align:right;">2</td><td style="text-align:right;">3</td><td style="text-align:right;">2</td></tr></tbody></table><h2 id="simple-role-card-version" tabindex="-1">Simple Role-Card Version <a class="header-anchor" href="#simple-role-card-version" aria-label="Permalink to &quot;Simple Role-Card Version&quot;">​</a></h2><p>For a simple game without printed Identity cards, the source suggests basic lands:</p><table tabindex="0"><thead><tr><th>Land</th><th>Role</th></tr></thead><tbody><tr><td>Plains</td><td>Leader</td></tr><tr><td>Island</td><td>Guardian</td></tr><tr><td>Mountain</td><td>Assassin</td></tr><tr><td>Swamp</td><td>Traitor</td></tr></tbody></table><h2 id="identity-rarity" tabindex="-1">Identity Rarity <a class="header-anchor" href="#identity-rarity" aria-label="Permalink to &quot;Identity Rarity&quot;">​</a></h2><p>Identities are sorted by rarity. Rarity indicates complexity rather than power level.</p><table tabindex="0"><thead><tr><th>Rarity</th><th>Use</th></tr></thead><tbody><tr><td>Uncommon</td><td>Recommended for first games.</td></tr><tr><td>Rare</td><td>Advanced identities.</td></tr><tr><td>Mythic</td><td>Expert identities.</td></tr><tr><td>Special / purple</td><td>Chaotic, high-impact identities that groups can include or exclude by taste.</td></tr></tbody></table><h2 id="game-materials" tabindex="-1">Game Materials <a class="header-anchor" href="#game-materials" aria-label="Permalink to &quot;Game Materials&quot;">​</a></h2><p>The site provides printable Identity cards and related files.</p><p>Available print/download formats include:</p><table tabindex="0"><thead><tr><th>Format</th><th>Notes</th></tr></thead><tbody><tr><td>A4-HQ</td><td>European A4 PDF, high-quality images, 9 cards per page.</td></tr><tr><td>A4-LQ</td><td>European A4 PDF, lower-quality images, 9 cards per page.</td></tr><tr><td>US-HQ</td><td>US Letter PDF, high-quality images, 9 cards per page.</td></tr><tr><td>US-LQ</td><td>US Letter PDF, lower-quality images, 9 cards per page.</td></tr><tr><td>IMG</td><td>Individual PNG images.</td></tr></tbody></table><p>The source notes that Treachery cards were designed with Magic Set Editor 2.5.6.</p><h2 id="treachery-2025-base-set" tabindex="-1">Treachery 2025 Base Set <a class="header-anchor" href="#treachery-2025-base-set" aria-label="Permalink to &quot;Treachery 2025 Base Set&quot;">​</a></h2><p>The listed 2025 base set includes:</p><ul><li>62 Identity cards.</li><li>3 custom tokens.</li><li>1 rule card.</li><li>English, French, German, and Spanish support.</li><li>Released June 30, 2025.</li></ul><p>Related local files:</p><ul><li><a href="treachery-cards-oracle.json">Treachery card oracle JSON</a></li><li><a href="./treachery-cards/">Treachery card images</a></li></ul><h2 id="banlist-notes" tabindex="-1">Banlist Notes <a class="header-anchor" href="#banlist-notes" aria-label="Permalink to &quot;Banlist Notes&quot;">​</a></h2><p>Treachery is meant to be played alongside another multiplayer format, usually Commander. It follows the banned/restricted list of the base format.</p><p>The source additionally suggests avoiding a few cards unless the table agrees ahead of time. The concern is that Treachery&#39;s political structure and universal starting-opponent status can make some cards especially disruptive.</p><p>Additional suggested avoids:</p><ul><li>Expropriate</li><li>Head Games</li><li>Trade Secrets</li></ul><h2 id="digital-tools" tabindex="-1">Digital Tools <a class="header-anchor" href="#digital-tools" aria-label="Permalink to &quot;Digital Tools&quot;">​</a></h2><p>The source mentions:</p><ul><li><strong>MTG Cloak</strong> as a newer web application for playing Treachery without printed cards.</li><li><strong>Treacherer</strong> as an older web application.</li><li>A Treachery Discord bot with <code>/help</code> support.</li></ul><h2 id="comprehensive-rules-summary" tabindex="-1">Comprehensive Rules Summary <a class="header-anchor" href="#comprehensive-rules-summary" aria-label="Permalink to &quot;Comprehensive Rules Summary&quot;">​</a></h2><p>The comprehensive rules are presented as an add-on to the official Magic Comprehensive Rules. They are not intended to be read from beginning to end; they are a reference for specific rules questions.</p><p>Important concepts include:</p><ul><li><strong>Identity</strong> is a custom card type used only for Treachery.</li><li>Identity cards remain in the command zone.</li><li>Identity cards are not permanents and cannot be cast or included in a deck.</li><li>Identity subtypes are also called identity types or roles.</li><li>The identity types are Leader, Guardian, Assassin, and Traitor.</li><li>The Leader subtype includes a static ability that makes its controller the starting player.</li><li>Face-down Identity cards have no characteristics.</li><li>A player may look at their own face-down Identity, but not another player&#39;s face-down Identity unless an ability allows it.</li></ul><h2 id="unveil" tabindex="-1">Unveil <a class="header-anchor" href="#unveil" aria-label="Permalink to &quot;Unveil&quot;">​</a></h2><p>Unveil is the core reveal mechanic.</p><p>In practical terms:</p><ul><li>Identity cards with Unveil can start face down in the command zone.</li><li>A player may unveil their face-down Identity when they have priority by paying its Unveil cost.</li><li>Unveiling is a special action and does not use the stack.</li><li>Many Identity cards trigger when unveiled.</li><li>When a player loses, their face-down Identity is revealed.</li><li>At the end of the game, all face-down Identities are revealed.</li></ul><h2 id="undercover" tabindex="-1">Undercover <a class="header-anchor" href="#undercover" aria-label="Permalink to &quot;Undercover&quot;">​</a></h2><p>Undercover is a special Unveil restriction, usually found on some Guardian Identities.</p><p>It generally means the Identity can be unveiled only if:</p><ul><li>Another non-Leader Identity card has been revealed; or</li><li>A player other than you attacked a Leader player this game.</li></ul><h2 id="treachery-rules-structure" tabindex="-1">Treachery Rules Structure <a class="header-anchor" href="#treachery-rules-structure" aria-label="Permalink to &quot;Treachery Rules Structure&quot;">​</a></h2><p>The formal Treachery variant rules define:</p><ul><li>A Treachery game as a multiplayer game with four or more players, best at five or six.</li><li>An Identity deck with exactly one Identity per player.</li><li>Exactly one Leader.</li><li>At least one Traitor.</li><li>Assassins equal to half the player count, rounded down.</li><li>Remaining slots filled by Guardians or Traitors.</li><li>The Identity distribution is known before the game begins.</li></ul><h2 id="teams" tabindex="-1">Teams <a class="header-anchor" href="#teams" aria-label="Permalink to &quot;Teams&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Identity</th><th>Team</th></tr></thead><tbody><tr><td>Leader</td><td>Leader team.</td></tr><tr><td>Guardian</td><td>Leader team.</td></tr><tr><td>Assassin</td><td>Assassin team.</td></tr><tr><td>Traitor</td><td>A solo team.</td></tr><tr><td>Face-down Identity</td><td>No teammates and considered opponents with other players until revealed.</td></tr></tbody></table><h2 id="winning-and-losing" tabindex="-1">Winning And Losing <a class="header-anchor" href="#winning-and-losing" aria-label="Permalink to &quot;Winning And Losing&quot;">​</a></h2><p>The comprehensive rules specify:</p><ul><li>A team loses if all players on that team have lost.</li><li>The Leader team loses if all Leaders have lost, even if Guardians remain.</li><li>The Assassin team wins if all Leaders have lost and at least one Assassin Identity remains in the game.</li><li>A Traitor wins if all of that Traitor&#39;s opponents have left the game, including other Traitors.</li><li>If any player on a team wins, their whole team wins.</li></ul><h2 id="leaving-the-game" tabindex="-1">Leaving The Game <a class="header-anchor" href="#leaving-the-game" aria-label="Permalink to &quot;Leaving The Game&quot;">​</a></h2><p>When a player leaves the game:</p><ul><li>Their face-down Identity must be revealed.</li><li>The game remembers their last known team.</li><li>Some Identity-related abilities or control-change effects may continue under the comprehensive rules.</li></ul><h2 id="source-legal-attribution-notes" tabindex="-1">Source Legal / Attribution Notes <a class="header-anchor" href="#source-legal-attribution-notes" aria-label="Permalink to &quot;Source Legal / Attribution Notes&quot;">​</a></h2><p>The source site states that Magic: The Gathering names, card images, mana symbols, and Oracle text belong to Wizards of the Coast / Hasbro, and that the site is not affiliated with Wizards.</p><p>The source also credits card artwork to the original illustrators, the Treachery logo to Ludovic Jordier, and several icons to game-icons.net.</p><p>Last update dates shown in the captured source:</p><ul><li>How to Play / Game Materials: June 30, 2025.</li><li>Comprehensive Rules: May 3, 2026.</li><li>Site/legal footer: May 6, 2026.</li></ul>',73)])])}const p=t(l,[["render",d]]);export{u as __pageData,p as default};
